import React, { useState } from 'react';

export default function AdminAuth() {
  const [username, setUsername] = useState('');
  const [pwd, setPwd] = useState('');
  const [msg, setMsg] = useState('');
  const [loading, setLoading] = useState(false);

  const handleAuth = (e) => {
    e.preventDefault();
    if (!username || !pwd) {
      setMsg('Fields must not be blank.');
      return;
    }
    setLoading(true);
    setMsg('');
    setTimeout(() => {
      setLoading(false);
      setMsg('Authorization pending security verification approval.');
    }, 1200);
  };

  return (
    <div className="p-5 bg-slate-900 border border-white/10 rounded-xl text-left max-w-xs w-full font-sans relative overflow-hidden">
      <h4 className="text-xs font-bold text-white uppercase tracking-wider">AURA SHIELD SECURE LOGIN</h4>
      <form onSubmit={handleAuth} className="space-y-3 mt-3">
        <input 
          type="text" 
          placeholder="Admin alias" 
          value={username} 
          onChange={e => setUsername(e.target.value)} 
          className="w-full bg-slate-950 border border-white/10 rounded px-3 py-1.5 text-xs text-white focus:outline-none" 
        />
        <input 
          type="password" 
          placeholder="Access token" 
          value={pwd} 
          onChange={e => setPwd(e.target.value)} 
          className="w-full bg-slate-950 border border-white/10 rounded px-3 py-1.5 text-xs text-white focus:outline-none" 
        />
        <button type="submit" className="w-full py-1.5 bg-[#a855f7] hover:bg-[#b05ff7] text-white rounded text-[10px] font-extrabold uppercase tracking-wide transition-all">
          {loading ? 'Authenticating...' : 'Enter Admin Vault'}
        </button>
        {msg && <p className="text-[9px] text-[#c084fc] font-mono leading-tight">{msg}</p>}
      </form>
    </div>
  );
}

import React, { useState } from 'react';

export default function CheckoutForm() {
  const [promo, setPromo] = useState('');
  const [disc, setDisc] = useState(0);
  const [promoMsg, setPromoMsg] = useState('');
  const basePrice = 280;

  const handlePromo = () => {
    if (promo.trim().toUpperCase() === 'COSMIC') {
      setDisc(40);
      setPromoMsg('Promo applied! $40 discount verified.');
    } else {
      setPromoMsg('Invalid promotional code.');
    }
  };

  return (
    <div className="p-5 bg-[#090912] border border-white/15 rounded-xl text-left max-w-xs w-full font-sans">
      <h4 className="text-xs font-bold text-white uppercase tracking-widest border-b border-white/5 pb-2">Checkout summary</h4>
      <div className="space-y-1.5 mt-3 text-[10px] text-slate-400">
        <div className="flex justify-between"><span>Quantum S4 Orb License</span><span className="font-mono">$280.00</span></div>
        {disc > 0 && <div className="flex justify-between text-emerald-400"><span>Aura Discount</span><span className="font-mono">-$40.00</span></div>}
        <div className="flex justify-between font-bold text-white pt-1.5 border-t border-white/5"><span>Total Value</span><span className="font-mono">$240.00</span></div>
      </div>

      <div className="flex gap-1 py-3">
        <input 
          placeholder="Promo: COSMIC" 
          value={promo} 
          onChange={e => setPromo(e.target.value)} 
          className="flex-1 bg-slate-950 border border-white/10 rounded px-2 py-1 text-[9px] text-white focus:outline-none" 
        />
        <button onClick={handlePromo} className="px-2 py-1 bg-white hover:bg-slate-100 text-[9px] font-extrabold rounded text-slate-950 uppercase">Apply</button>
      </div>
      {promoMsg && <p className="text-[9px] text-purple-400 font-mono mb-2.5 leading-none">{promoMsg}</p>}

      <button className="w-full py-1.5 bg-emerald-400 hover:bg-emerald-300 text-slate-950 font-extrabold rounded text-[10px] uppercase transition-all tracking-wide">
        Lock Final Order
      </button>
    </div>
  );
}

